SELECT r.id, r.employee_id, r.room_id, r.checkin_date, r.expected_checkout_date, r.checkout_date, r.checkout_reason, r.status, r.created_at, e.name AS employee_name, e.employee_no, e.type AS employee_type, rm.name AS room_name, d.name AS dormitory_name FROM residences r INNER JOIN employees e ON e.id = r.employee_id INNER JOIN rooms rm ON rm.id = r.room_id INNER JOIN dormitories d ON d.id = rm.dormitory_id
AND r.status = #{status}
AND (e.name LIKE CONCAT('%', #{keyword}, '%') OR e.employee_no LIKE CONCAT('%', #{keyword}, '%') OR d.name LIKE CONCAT('%', #{keyword}, '%'))
AND r.checkin_date >= #{checkinFrom}
AND r.checkin_date <= #{checkinTo}
ORDER BY r.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM residences r INNER JOIN employees e ON e.id = r.employee_id INNER JOIN rooms rm ON rm.id = r.room_id INNER JOIN dormitories d ON d.id = rm.dormitory_id
AND r.status = #{status}
AND (e.name LIKE CONCAT('%', #{keyword}, '%') OR e.employee_no LIKE CONCAT('%', #{keyword}, '%') OR d.name LIKE CONCAT('%', #{keyword}, '%'))
AND r.checkin_date >= #{checkinFrom}
AND r.checkin_date <= #{checkinTo}

